以下のコードをコピーして `.html` ファイルとして保存してください。

```html
<!DOCTYPE html>
<html lang="ja">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>ランダムジョーク</title>
  <style>
    /* ========== リセット & 基本設定 ========== */
    *, *::before, *::after {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      min-height: 100vh;
      display: flex;
      justify-content: center;
      align-items: center;
      background: linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%);
      font-family: "Segoe UI", "Helvetica Neue", Arial, sans-serif;
      color: #ffffff;
    }

    /* ========== カード ========== */
    .card {
      background: rgba(255, 255, 255, 0.07);
      backdrop-filter: blur(12px);
      -webkit-backdrop-filter: blur(12px);
      border: 1px solid rgba(255, 255, 255, 0.15);
      border-radius: 24px;
      padding: 48px 40px;
      max-width: 520px;
      width: 90%;
      text-align: center;
      box-shadow: 0 24px 60px rgba(0, 0, 0, 0.4);
    }

    /* ========== タイトル ========== */
    .title {
      font-size: 2rem;
      font-weight: 700;
      letter-spacing: 0.04em;
      margin-bottom: 8px;
    }

    .title span {
      display: inline-block;
      animation: wobble 2s infinite;
    }

    .subtitle {
      font-size: 0.9rem;
      color: rgba(255, 255, 255, 0.55);
      margin-bottom: 36px;
    }

    /* ========== ジョーク表示エリア ========== */
    .joke-box {
      background: rgba(255, 255, 255, 0.05);
      border: 1px solid rgba(255, 255, 255, 0.1);
      border-radius: 16px;
      padding: 28px 24px;
      min-height: 120px;
      display: flex;
      flex-direction: column;
      justify-content: center;
      align-items: center;
      gap: 12px;
      margin-bottom: 32px;
      transition: all 0.3s ease;
    }

    .joke-emoji {
      font-size: 2.4rem;
      line-height: 1;
      opacity: 0;
      transform: scale(0.5);
      transition: opacity 0.4s ease, transform 0.4s ease;
    }

    .joke-text {
      font-size: 1.05rem;
      line-height: 1.7;
      color: rgba(255, 255, 255, 0.9);
      opacity: 0;
      transform: translateY(10px);
      transition: opacity 0.4s ease 0.1s, transform 0.4s ease 0.1s;
    }

    .joke-placeholder {
      font-size: 0.95rem;
      color: rgba(255, 255, 255, 0.35);
      font-style: italic;
    }

    /* 表示時のクラス */
    .joke-box.visible .joke-emoji {
      opacity: 1;
      transform: scale(1);
    }

    .joke-box.visible .joke-text {
      opacity: 1;
      transform: translateY(0);
    }

    /* ========== ボタン ========== */
    .btn {
      position: relative;
      display: inline-block;
      padding: 14px 36px;
      font-size: 1rem;
      font-weight: 600;
      color: #ffffff;
      background: linear-gradient(135deg, #e94560 0%, #c2185b 100%);
      border: none;
      border-radius: 50px;
      cursor: pointer;
      overflow: hidden;
      transition: transform 0.15s ease, box-shadow 0.15s ease;
      box-shadow: 0 6px 20px rgba(233, 69, 96, 0.45);
      letter-spacing: 0.04em;
    }

    .btn::after {
      content: "";
      position: absolute;
      inset: 0;
      background: rgba(255, 255, 255, 0);
      transition: background 0.2s ease;
    }

    .btn:hover {
      transform: translateY(-3px);
      box-shadow: 0 10px 28px rgba(233, 69, 96, 0.55);
    }

    .btn:hover::after {
      background: rgba(255, 255, 255, 0.08);
    }

    .btn:active {
      transform: translateY(0px);
      box-shadow: 0 4px 12px rgba(233, 69, 96, 0.35);
    }

    /* ========== カウンター ========== */
    .counter {
      margin-top: 20px;
      font-size: 0.8rem;
      color: rgba(255, 255, 255, 0.35);
    }

    .counter span {
      color: rgba(255, 255, 255, 0.65);
      font-weight: 600;
    }

    /* ========== アニメーション ========== */
    @keyframes wobble {
      0%, 100% { transform: rotate(0deg); }
      20%       { transform: rotate(-10deg); }
      40%       { transform: rotate(10deg); }
      60%       { transform: rotate(-6deg); }
      80%       { transform: rotate(6deg); }
    }

    @keyframes pop {
      0%   { transform: scale(1); }
      50%  { transform: scale(1.15); }
      100% { transform: scale(1); }
    }

    .pop {
      animation: pop 0.3s ease;
    }
  </style>
</head>
<body>

  <div class="card">
    <!-- タイトル -->
    <h1 class="title"><span>😂</span> ジョークBOT</h1>
    <p class="subtitle">ボタンを押してランダムなジョークをゲットしよう！</p>

    <!-- ジョーク表示エリア -->
    <div class="joke-box" id="jokeBox">
      <p class="joke-placeholder" id="placeholder">← ボタンを押してみよう！</p>
      <span class="joke-emoji" id="jokeEmoji"></span>
      <p class="joke-text" id="jokeText"></p>
    </div>

    <!-- ボタン -->
    <button class="btn" id="jokeBtn" onclick="showJoke()">
      🎲 ジョークを見る
    </button>

    <!-- 表示カウンター -->
    <p class="counter">これまでに <span id="count">0</span> 回笑いました 🤣</p>
  </div>

  <script>
    // ========== ジョークデータ ==========
    const jokes = [
      {
        emoji: "🐄",
        text: "牛が「モ〜」と鳴きました。\nなぜなら、牛は「ファ〜」とは言えないからです。"
      },
      {
        emoji: "🔦",
        text: "懐中電灯が学校を辞めました。\n理由は「もう十分、明るい未来が見えてきた」から。"
      },
      {
        emoji: "🍣",
        text: "寿司が二つ並んでいました。\n片方が「最近どう？」と聞くと、\nもう片方が「まぁ、なんとかネタが尽きてない感じ」と答えました。"
      },
      {
        emoji: "🤖",
        text: "プログラマーが妻に言いました。\n「買い物に行って、牛乳を1本買ってきて。\n卵があったら6個買ってきて」\n妻は牛乳を6本買って帰ってきました。"
      }
    ];

    let count = 0;
    let lastIndex = -1;

    function showJoke() {
      // 前回と違うジョークを選ぶ
      let index;
      do {
        index = Math.floor(Math.random() * jokes.length);
      } while (index === lastIndex && jokes.length > 1);
      lastIndex = index;

      const joke = jokes[index];
      const box  = document.getElementById("jokeBox");
      const emoji = document.getElementById("jokeEmoji");
      const text  = document.getElementById("jokeText");
      const ph    = document.getElementById("placeholder");
      const btn   = document.getElementById("jokeBtn");

      // リセットアニメーション
      box.classList.remove("visible");

      setTimeout(() => {
        // プレースホルダーを非表示
        ph.style.display = "none";

        // 内容をセット
        emoji.textContent = joke.emoji;
        text.textContent  = joke.text;

        // 表示アニメーション
        box.classList.add("visible");
      }, 200);

      // ボタンのポップアニメーション
      btn.classList.remove("pop");
      void btn.offsetWidth; // reflow
      btn.classList.add("pop");

      // カウンターを更新
      count++;
      document.getElementById("count").textContent = count;
    }
  </script>

</body>
</html>
```

---

## 機能の説明

| 機能 | 詳細 |
|---|---|
| **ランダム表示** | 4つのジョークからランダムに1つを選択 |
| **連続防止** | 直前と同じジョークは選ばれない |
| **アニメーション** | ジョークがフェードインしてスムーズに登場 |
| **カウンター** | 何回ボタンを押したか記録・表示 |
| **レスポンシブ** | スマホ・PCどちらでも見やすいレイアウト |

## 使い方

1. コードをコピーして `joke.html` という名前で保存
2. ブラウザで開く
3. **「🎲 ジョークを見る」** ボタンをクリック！
